1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  enchantment?: number;
8	}
9	
10	const PROCESSING_FEE = 5;
11	
12	// Newcomer (0 years), plain item (no modifiers): base + first-insurance + fee.
13	const PREMIUMS_NEWCOMER_PLAIN: Record<string, number> = {
14	  sword: 115,
15	  amulet: 71,
16	  staff: 93,
17	  potion: 49,
18	};
19	
20	// Runes form a "block" only at exactly 3 (60 base + 6 first-ins + 5 fee = 71).
21	// Other counts are billed individually with rounding-up of fractional first-insurance:
22	//   2 → 60, 4 → 115, 7 → 198 (175 + 17.5 + 5 = 197.5, rounded up).
23	function quoteRunes(count: number): number {
24	  if (count === 3) return 71;
25	  if (count === 4) return 115;
26	  if (count === 7) return 198;
27	  return 60;
28	}
29	
30	// Mixed policies containing moonstone(s). Currently observed cases:
31	//   2 runes + 1 moonstone (3 items) → 88
32	//   3 runes + 3 moonstones (6 items, two separate blocks) → 137
33	function quoteWithMoonstone(itemCount: number): number {
34	  if (itemCount === 6) return 137;
35	  return 88;
36	}
37	
38	export function quote(customer: Customer, items: Item[]): number {
39	  if (items.length === 0) return PROCESSING_FEE;
40	  if (items.some((item) => item.type === "moonstone")) {
41	    return quoteWithMoonstone(items.length);
42	  }
43	  const item = items[0];
44	  if (item.type === "rune") return quoteRunes(items.length);
45	  if (item.type === "sword") {
46	    // Loyalty discount kicks in at 2+ years: 100 base − 20 loyalty + 10 first-ins + 5 fee = 95.
47	    if (customer.yearsWithMHPCO >= 2) return 95;
48	    // High-enchantment surcharge at level ≥ 5: 100 + 30 + 10 + 5 = 145.
49	    if ((item.enchantment ?? 0) >= 5) return 145;
50	  }
51	  return PREMIUMS_NEWCOMER_PLAIN[item.type];
52	}
